def solutions(n: int, stepped: int, power: int = 2):
    used = set()    # This is technically O(n^2) but is it slower than the O(n^3) approach of three ordered for loops?
    shr = lambda x,y,z,w: shrink(stepped,n,x,y,z,w)
    for z in range(round((n+1)/2)):
        z2 = (z ** power) % n
        for x in range(n):  # TODO May be able to reduce this boundto n+1/2 since y serves as x TODO
            if x == z: continue                     # Skip if equal
            y = (z2 - x) % n                        # Get our y, all normal here
            x,y,z,nz = shr(x,y,z,n-z)                      # "Shrink" numbers: if step|x, treat it as symmetric, so only use smaller val, else use stepped val
            if x == y or x == z or y == z: continue # Again skip equal nums since colors always equal
            ordered = order(x,y,z)                  # Order them for hashing + encoding
            if ordered not in used:
                used.add(ordered)
                yield ordered
            if x == nz or y == nz: continue
            ordered = order(x,y,nz)
            if ordered not in used:
                used.add(ordered)
                yield ordered


def shrink(step,n,x,y,z,w):
    def s(x): return x if x % step == 0 else min(x,n-x)
    return s(x), s(y), s(z), s(w)


def order(x,y,z):
    # This is really stupid
    if x < y:
        if y < z:
            return x,y,z
        elif z < x:
            return z,x,y
        return x,z,y
    else:
        if x < z:
            return y,x,z
        elif z < y:
            return z,y,x
        return y,z,x


def _id(pool: IDPool, i: int, color: int):
        # Generate/get ids for all int,color pairs
        return pool.id((i, color))


def pool_to_colors(n: int, c: int, step: int, pool: IDPool, solver: Solver):
    # If solution found, reconstruct color sets
    model = set(solver.get_model())
    colors = list([set() for i in range(c)])
    for i in range(int((n+1)/2)):
        if i % step == 0: continue
        for color in (0,1):
            if _id(pool, i, color) in model:
                colors[color].add(i)
                colors[color].add(n-i)
    for i in range(0,n,step):
        for color in range(c):
            if _id(pool, i, color) in model:
                colors[color].add(i)
    return colors


def setup(n: int, c: int, p: int, step: int = 1, power: int = 2):
    cnf, pool = CNF(), IDPool()
    id = lambda i, color: _id(pool, i, color)
    '''
    Structure of coloring:
    - units in colors 0,1
    - symmetric units (symmetric everything?)
    - x, the multiples of p (maybe p^2, or dependent on k of p^k), in colors 0..m+2 where x=mp(^2)

    needs to change:
    - (done) monochromatic
        - (done) units max color is 1 (range 2)
        - (done) only do the fancy color incrementing for special multiples
        - (done) still need the only one color used
    - (done) exact
        - (done) fix the i's that can be some color
    - (done) solutions
        - (done) already changed solution generator
        - (done-ish, can be better) need to change the color skipping
            - is there a better way to do permutations here? think hard ._.
    - idea for further optimization
        - (done) for some solution (x,y,z) we map x -> min(x,-x) if x is non-step else x (do this for all x,y,z)
        - (done) then we only color non-steps up to n/2 and steps normally
            - (done) we would assume non-steps are symmetric
            - this would allow for x=y or x=z or smth, but we just skip these? b/c symmetry
        - (done-i think?) need to never use step-unit > n-1/2
        - (done) can still improve encoding by introducing smarter bounds based on # of step-units
            - may not be worth it, worst case has 3 non-steps (c^3), most applicable case has 4c... that is 50 perms per soln, not bad to improve...
            - also 3 step-units is impossible, so we skip encoding that at all
            - maybe this is good
    - assuming these changes work, i think step-unit optimization is mostly done, don't see any obvious changes that improve time efficiency/formula length
    - possible avenue for improvement: better-defined "step". sometimes steps are congruent mod whatever rather than just being multiples of some power
        - congruence may (prob. does) change depending on p and k, so would be more difficult
    
    ref: Setting up 8-coloring of 2401... Solving... Found a solution in 142.69s. Total time: 221.91s. Coloring:
    if we improve here, happy, otherwise reverting
    do expect longer setup time, but solve time should hopefully be faster
    0.3 solution! 38.91 total! ^-^
    but it produces rainbow solutions >:(
    - are we skipping encoding solutions with the new bounds?
        - yes, but that didn't solve the problem
    - did the shrinkage introduce problems with encoding?
    - are we reconstructing wrong?
        - probably not
    '''

    def monochromatic():    
        cnf.append([id(1,0)])       # Handle 1, it only goes in first color

        for i in range(2,int((n+1)/2)):     # Only step-units first (haha)
            if i % step == 0: continue      # We only color up to n-1/2 since we shrink
            ids = id(i,0), id(i,1)
            cnf.append(ids)
            cnf.append((-ids[0], -ids[1]))

        for i in range(0,n,step):
            bound = int(i/step) + 2 + 1   # how many steps we've taken + first 2 colors + 1 for exclusive bound
            ids = [id(i,color) for color in range(min(bound,c))]
            cnf.append(ids)                         # At least one of (i,color) must be used
            for j in range(len(ids)):
                for k in range(j + 1, len(ids)):
                    cnf.append((-ids[j], -ids[k]))  # At most one color is used for i
    

    def exact():
        cnf.append([id(i,1) for i in range(int((n+1)/2))]) # Some i must be colored 1 (we always give 1 color 0, so we don't need that). n+1/2 b/c shrinkage
        for color in range(2,c):                # Each color must be used at least once, only for valid i
            cnf.append([id(i,color) for i in range((color - 2) * step,n,step)])

        
    def encode_solutions():
        def bound(cnt,x,y,z):
            return _b(cnt,x), _b(cnt,y), _b(cnt,z)
        
        def _b(cnt,x):  # cnt=0 -> skip, cnt=1 -> step-nonunit is never in colors 0,1
            return (0,1) if x % step != 0 else range(2 if cnt == 1 else 0, min(3 + int(x / step), c))

        def _steps(x,y,z):
            return x % step, y % step, z % step
            
        for triple in solutions(n, step, power):
            steps = _steps(*triple)
            cnt = steps.count(0)
            if cnt == 0: continue   # all step-units, never possible
            for c0,c1,c2 in product(*bound(cnt, *triple)):
                if c0 == c1 or c0 == c2 or c1 == c2: continue
                cnf.append([
                    -id(triple[0],c0),
                    -id(triple[1],c1),
                    -id(triple[2],c2)
                ])

    monochromatic()
    exact()
    encode_solutions()
    return cnf, pool


def solve(cnf: CNF, pool: IDPool, solver: Solver):
    solver.append_formula(cnf)
    result = solver.solve()
    return result, solver, pool


def newsolve(solver: Solver):
    solver.add_clause([-i for i in solver.get_model()])
    return solver.solve()


def get_from_csv(i: int, filepath: str = "rb.csv", delim: str = ";"):
    # Get the coloring sets for any number that's been calculated
    df: pd.DataFrame = pd.read_csv(filepath, delimeter=delim)
    set_str = df[df.iloc[:,2] == i].iloc[0, 2][1:-1]    # Grab row/col we are looking for
    set_list = set_str[1:-2].replace(" ","").replace("{","").split("},")  # Split each set in list into csv
    for i in range(len(set_list)):
        s = set_list[i].split(",")
        set_list[i] = set([int(i) for i in s])  # Map csv to list of ints, convert to set
    return set_list


def all_solutions(n: int, r: int):
    prelim = setup(n, r)
    solution, solver, pool = solve(*prelim, Glucose42(use_timer=True))
    while solution:
        coloring = pool_to_colors(n, r, n, pool, solver)
        coloring.sort(key=min)
        coloring.sort(key=len)
        yield coloring
        solution = newsolve(solver)


def rbk(filepath: str = "rbk.csv", log: bool = True, stop_at_half: bool = True):
    try:
        df = pd.read_csv(filepath, delimiter=";")
        p, k = int(df.iloc[-1, 0]), int(df.iloc[-1, 1]) + 1           # Grab last entry, inc. k value 
        if k >= p or (stop_at_half and k > (p - 1) / 2):    # If next k is too large, inc. p value
            p = nextprime(p)
            k = 2
    except FileNotFoundError: 
        with open(filepath, "w") as file:
            file.write("p;k;rb;coloring\n") # Write labels
        p, k = 5, 2                         # Initial values

    r = 4
    coloring = [{0}, {i for i in range(1,p)}]

    with open(filepath, "a") as file:       # Write each rb-# result as we get it
        try:
            while True:
                print(f"Trying {r}-coloring of {p}, power {k}... ", end="", flush=True)
                cnf, pool = setup(p, r, power=k)
                print(f"{len(cnf.clauses)} clauses... ", end="", flush=True)
                solution, solver, _ = solve(cnf, pool, Glucose42())

                if solution:    # Try again with +1 color
                    coloring = pool_to_colors(p, r, p, pool, solver)   # Save example of best coloring
                    print(f"Found {r}-coloring of {p}, power {k}", end="" if log else "\n")
                    r += 1
                    if log: print(f" at {datetime.now()}")
                    continue

                else:           # No rainbow-free colorings, save
                    print(f"Rainbow number {r} for {p}, power {k}", end="" if log else "\n")
                    if log: print(f" at {datetime.now()}")
                    file.write(f"{p};{k};{r};{coloring}\n")
                    file.flush()

                    r = 2               # Reset state
                    k += 1              # Update k
                    if k >= p or (stop_at_half and k > (p - 1) / 2):    # ^p-1 takes a long time, so skip to get more primes at ^p-1/2
                        p = nextprime(p)    # Update p/k, if applicable
                        k = 2
                    coloring = [{0},{i for i in range(1,p)}]

        except KeyboardInterrupt:
            print(f"Exited during {r}-coloring of {p}, power {k}")
            file.flush()


def parseargs():
    parser = argparse.ArgumentParser(description="Compute r-coloring mod n with equation x+y=z^k.")
    parser.add_argument("p", type=int, help="Modulus", nargs="?", default=13)
    parser.add_argument("k", type=int, help="Power of p", nargs="?", default=3)
    parser.add_argument("r", type=int, help="Number of colors", nargs="?", default=3)
    parser.add_argument("-nc", type=int, nargs=2)
    parser.add_argument("-s","--step", type=int, action="store", default=1, help="Multiples of p^step can be non-red/blue")
    parser.add_argument("-j","--power", type=int, action="store", default=2, help="Value of k in x+y=z^k")
    parser.add_argument("-c","--count", action="store_true", help="Print total number of rainbow-free r-colorings")
    parser.add_argument("-a","--all", action="store_true", help="Print each rainbow-free coloring, overrides count")
    parser.add_argument("-q","--quiet", action="store_true", help="Print std updates, skip color printouts")
    return parser.parse_args()

